import{c as a,Q as t,j as s,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Platform Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/architecture.md","filePath":"guide/concepts/architecture.md","lastUpdated":1778912818000}'),r={name:"guide/concepts/architecture.md"};function o(i,e,l,c,h,d){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="platform-architecture" tabindex="-1">Platform Architecture <a class="header-anchor" href="#platform-architecture" aria-label="Permalink to &quot;Platform Architecture&quot;">​</a></h1><p>The Console is a control plane. It does not run your customers&#39; workloads — those run on <em>instances</em>. Instead, the Console tracks who owns what, what should be running where, and what each customer is paying for.</p><p>This page is a conceptual map. It is intentionally light on implementation detail.</p><h2 id="the-data-hierarchy" tabindex="-1">The data hierarchy <a class="header-anchor" href="#the-data-hierarchy" aria-label="Permalink to &quot;The data hierarchy&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Customer ──┬── Tenants ── Users (assigned per tenant)</span></span>
<span class="line"><span>           ├── Plan (with meter limits)</span></span>
<span class="line"><span>           ├── Invoices, Payments, Credits</span></span>
<span class="line"><span>           └── Settings (auth, MFA, IdP, webhooks)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Instance ──┬── Tenants (provisioned here)</span></span>
<span class="line"><span>           ├── Services (running pods)</span></span>
<span class="line"><span>           └── Environment Variables (with overrides)</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Diagram</p><p><em>Replace the ASCII tree with a clean architecture diagram</em> showing Customer / Tenant / Instance / Plan / Meter and their relationships. Suggest a left-to-right layered diagram.</p></div><ul><li><strong>Customer.</strong> The company you sell to. The unit of contracting and billing. A customer has a plan, a billing contact, and a portal.</li><li><strong>Tenant.</strong> A logical environment owned by a customer. Tenants are where the customer&#39;s own users sign in to use Exto&#39;s products. A customer typically has one tenant per environment (DEV, QA, PROD).</li><li><strong>Instance.</strong> A hosted environment that runs tenants — a Kubernetes cluster or hosted backend. Instances have a region, capacity (max tenants), and a fleet of services with versioned Docker images.</li><li><strong>Plan.</strong> A pricing template that defines included quantities per meter and overage rates.</li><li><strong>Meter.</strong> A measurable unit of usage (<code>api_calls</code>, <code>storage_gb</code>, <code>active_users</code>). Plans bind meters to limits and prices.</li></ul><h2 id="how-the-surfaces-relate" tabindex="-1">How the surfaces relate <a class="header-anchor" href="#how-the-surfaces-relate" aria-label="Permalink to &quot;How the surfaces relate&quot;">​</a></h2><p>The Console exposes two UIs over the same data:</p><ul><li>The <strong>Admin Console</strong> is the operator view. Operators see every customer, every tenant, every instance, every release. They can suspend, archive, move, migrate, override, and so on.</li><li>The <strong>Customer Portal</strong> is the customer view. Customer admins see only their customer&#39;s tenants, users, billing, and changelog. They can configure their own auth policy and invite users — but they cannot see other customers&#39; data and cannot operate the underlying infrastructure.</li></ul><p>Both surfaces use the same backend, the same auth, and the same audit log. Every action either surface takes is recorded against the actor that performed it.</p><h2 id="the-release-pipeline" tabindex="-1">The release pipeline <a class="header-anchor" href="#the-release-pipeline" aria-label="Permalink to &quot;The release pipeline&quot;">​</a></h2><p>Releases are how new code and configuration reach instances:</p><ol><li>An operator creates a <strong>release</strong> — a versioned bundle of service images and/or environment-variable changes.</li><li>The release flows through a <strong>pipeline</strong> of stages. Each stage groups one or more environments (e.g. DEV → QA → PROD). Within a stage, environments may deploy in parallel.</li><li>Stages may require <strong>approval</strong> from designated SPOCs and an explicit <strong>trigger</strong> before progressing.</li><li>The Console pushes the release to each matching instance. The instance agent acknowledges deployment, success, or failure.</li></ol><p>The release configuration (managed services, pipeline stages, approval rules, SLA thresholds, escalation contacts) is global to the platform and lives on the Release Configuration page.</p><h2 id="identity" tabindex="-1">Identity <a class="header-anchor" href="#identity" aria-label="Permalink to &quot;Identity&quot;">​</a></h2><p>Sign-in is brokered by Zitadel. The Console never sees passwords directly.</p><ul><li>Each <strong>customer organisation</strong> in the Console maps to a Zitadel org.</li><li>Each user belongs to one home org but can be granted access to other customers as a partner / portal user.</li><li>Customers can configure their own <strong>identity providers</strong> (Google, Azure AD, custom OIDC) and their own <strong>password and MFA policy</strong>, all through the Customer Portal.</li></ul><h2 id="what-lives-outside-this-guide" tabindex="-1">What lives outside this guide <a class="header-anchor" href="#what-lives-outside-this-guide" aria-label="Permalink to &quot;What lives outside this guide&quot;">​</a></h2><p>This guide describes what the UI does. The mechanics of how the Console talks to instances, how the agent pushes deployments, how Zitadel is configured, how migration jobs are executed, and the deployment topology of the Console itself are all engineering concerns. They live in the internal documentation.</p>`,20)])])}const g=a(r,[["render",o]]);export{u as __pageData,g as default};
